import React from 'react';

const ContactoPage = () => {
  // URLs e imágenes
  const mainImage = {
    src: '/media/contactoPage/UCBA.png',
    alt: 'Entrada UCB',
    link: 'https://www.ucb.edu.bo/',
  };

  const rightImages = [
    {
      src: '/media/contactoPage/SISE.png',
      alt: 'Logo SIS',
      link: 'https://www.ucb.edu.bo/contacto',
    },
    {
      src: '/media/contactoPage/ADM - H.png',
      alt: 'Equipo ADM',
      link: 'https://www.ucb.edu.bo/nosotros',
    },
  ];

  return (
    <main style={styles.page}>
      <div style={styles.container}>
        <h1 style={styles.title}>UNIVERSIDAD CATÓLICA BOLIVIANA</h1>

        {/* Contenedor fila grande */}
        <div style={styles.bigRow}>
          {/* Imagen grande izquierda */}
          <a href={mainImage.link} target="_blank" rel="noopener noreferrer" style={styles.mainImageLink}>
            <img src={mainImage.src} alt={mainImage.alt} style={styles.mainImage} />
          </a>

          {/* Contenedor vertical derecho con 2 imágenes */}
          <div style={styles.rightColumn}>
            {rightImages.map(({ src, alt, link }, idx) => (
              <a
                key={idx}
                href={link}
                target="_blank"
                rel="noopener noreferrer"
                style={styles.rightImageLink}
              >
                <img src={src} alt={alt} style={styles.rightImage} />
              </a>
            ))}
          </div>
        </div>
      </div>
    </main>
  );
};

const styles = {
  page: {
    backgroundColor: '#F8F0E3',
    minHeight: '100vh',
    padding: '3rem 1rem',
    fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
  },
  container: {
    maxWidth: 960,
    margin: '0 auto',
    color: '#052018',
    padding: '0 1rem',
  },
  title: {
    fontSize: '3rem',
    fontWeight: '900',
    marginBottom: '2rem',
    textAlign: 'center',
    color: '#052018',
  },

  bigRow: {
    display: 'flex',
    gap: '1.5rem',
    alignItems: 'stretch', // Para que alturas se igualen
  },

  mainImageLink: {
    flex: '1 1 60%',
    maxWidth: '60%',
    display: 'block',
  },
  mainImage: {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
    borderRadius: 16,
    boxShadow: '0 2px 12px rgba(0,0,0,0.15)',
    display: 'block',
  },

  rightColumn: {
    flex: '1 1 40%',
    display: 'flex',
    flexDirection: 'column',
    gap: '1.5rem',
  },

  rightImageLink: {
    flex: '1 1 50%',
    display: 'block',
  },
  rightImage: {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
    borderRadius: 16,
    boxShadow: '0 2px 12px rgba(0,0,0,0.15)',
    display: 'block',
  },
};

export default ContactoPage;
